sql:
SELECT us_canada_size, circumference_inches, eu_size, created_at
FROM ring_sizes
ORDER BY created_at DESC;

SELECT product_id
FROM ring_products
WHERE ring_size_id = 1;

SELECT AVG(price) AS average_price
FROM ring_products
WHERE material = 'gold' AND stock_level BETWEEN 5 AND 20;

SELECT us_canada_size
FROM ring_sizes
WHERE ring_size_id = 1;

external_knowledge:
- "top customers" refers to those who spent the most in the past month;
- "frequent purchases" implies counting the number of orders made by each customer;
- "past month" means the last 30 days from the current date.

